            modelBuilder.Entity("DockingDataModels.Docking", b =>
                {
                    b.Property<long>("Id")
                        .ValueGeneratedOnAdd()
                        .HasColumnType("INTEGER");

                    b.Property<string>("BindingCavity")
                        .HasColumnType("TEXT");

                    b.Property<long>("Created")
                        .HasColumnType("INTEGER");

                    b.Property<string>("DockingProgram")
                        .HasColumnType("TEXT");

                    b.Property<long>("LigandPdbqtHash")
                        .HasColumnType("INTEGER");

                    b.Property<string>("ProteinId")
                        .HasColumnType("TEXT");

                    b.Property<long>("ReceptorPdbqtHash")
                        .HasColumnType("INTEGER");

                    b.Property<float>("Score")
                        .HasColumnType("REAL");

                    b.Property<string>("SearchingSpace")
                        .HasColumnType("TEXT");

                    b.Property<string>("Smiles")
                        .HasColumnType("TEXT");

                    b.Property<int>("StructureIndex")
                        .HasColumnType("INTEGER");

                    b.HasKey("Id");

                    b.ToTable("Dockings");
                });

