                            Id = "dakb-gpcrs",
                            Citation = "**DAKB-GPCRs: An Integrated Computational Platform for Drug Abuse Related GPCRs**  \nMaozi Chen, Yankang Jing, Lirong Wang, Zhiwei Feng, Xiang-Qun Xie  \n*Journal of Chemical Information and Modeling*, 2019, 59(4), pp 1283-1289  \nPublication Date: March 5, 2019  \nhttps://doi.org/10.1021/acs.jcim.8b00623  \nhttps://pubmed.ncbi.nlm.nih.gov/30835466/",
                            Created = 636503616000000000L,
                            Description = "DAKB-GPCRs is a knowledgebase for drug abuse research that implemented with our established chemogenomics tools as well as our algorithms for data visualization and analyses. This tool predicts the BioActivities on 86 drug abuse related GPCRs (G Protein-Coupled Receptors) for a query compound and provides a handy user interface for viewing, downloading and plotting the output results.",
                            IsPublic = true,
