                        .IsRequired();

                    b.HasOne("DockingDataModels.Job", "Job")
                        .WithMany("Results")
                        .HasForeignKey("JobId")
                        .OnDelete(DeleteBehavior.Cascade)
                        .IsRequired();

                    b.HasOne("DockingDataModels.Ligand", "Ligand")
